// src/components/Sidebar.jsx
import React from 'react';
import {
  Home,
  CalendarDays,
  BookOpen,
  Users,
  UserRound,
  Mail,
  Settings,
  HelpCircle,
  Box,
  PackagePlus,
  PieChart,
  LayoutList,
  // ... demais ícones
} from 'lucide-react';
import { MenuItem } from './MenuItem';

export function Sidebar({ active, onMenuClick }) {
  return (
    <aside
      className="
        flex flex-col justify-between
        w-full md:w-64
        h-screen bg-white
        md:fixed top-0 left-0
        z-30 print:hidden
      "
    >
      {/* Topo: menu principal */}
      <nav className="flex flex-col gap-2 mt-24 px-4">
        <MenuItem
          icon={<Home size={24} />}
          label="Dashboard"
          path="/"
          isActive={active === 'dashboard'}
          onClick={() => onMenuClick('dashboard')}
        />
        <MenuItem
          icon={<CalendarDays size={24} />}
          label="Agendamentos"
          path="/agendamentos"
          isActive={active === 'agendamentos'}
          onClick={() => onMenuClick('agendamentos')}
        />
        {/* ... demais itens */}
      </nav>

      {/* Rodapé: configurações, ajuda */}
      <div className="mb-4 px-4">
        <MenuItem
          icon={<Settings size={24} />}
          label="Configurações"
          path="/settings"
          isActive={active === 'settings'}
          onClick={() => onMenuClick('settings')}
        />
        <MenuItem
          icon={<HelpCircle size={24} />}
          label="Ajuda"
          path="/help"
          isActive={active === 'help'}
          onClick={() => onMenuClick('help')}
        />
      </div>
    </aside>
  );
}

export default Sidebar;
